+                  {a.name}
+                </div>
+                <div style={{ fontSize: 10, color: 'var(--text-secondary)', margin: '2px 0 6px' }}>
+                  {a.source}
+                </div>
+                <div style={{ fontSize: 12, color: 'var(--text-primary)', lineHeight: 1.4 }}>
+                  {artifactSummary(a)}
+                </div>
+              </div>
+            ))}
+          </div>
+        )}
